SELECT id, code, name, region, contact, phone, active, version_ids, created_at, updated_at FROM sites
(name ILIKE CONCAT('%', #{keyword}, '%') OR region ILIKE CONCAT('%', #{keyword}, '%') OR code ILIKE CONCAT('%', #{keyword}, '%'))
ORDER BY name ASC LIMIT #{limit} OFFSET #{offset}

SELECT id, code, name, region, contact, phone, active, version_ids, created_at, updated_at
FROM sites
WHERE id = #{id}

SELECT id, code, name, region, contact, phone, active, version_ids, created_at, updated_at
FROM sites
WHERE name = #{name}
